# tests/fitness/test_token_budget_declared.py
import pathlib, yaml, pytest

PROMPTS_DIR = pathlib.Path("prompts")

def collect_templates():
    return list(PROMPTS_DIR.rglob("*.yml"))

@pytest.mark.parametrize("template_path", collect_templates())
def test_token_budget_declared(template_path):
    with open(template_path) as f:
        template = yaml.safe_load(f)

    missing = []
    if "max_input_tokens" not in template:
        missing.append("max_input_tokens")
    if "max_output_tokens" not in template:
        missing.append("max_output_tokens")

    assert not missing, (
        f"{template_path}: missing required token budget fields: {missing}. "
        f"Add these fields to declare the cost contract for this template."
    )

# tests/fitness/test_max_tokens_explicit.py
import ast, pathlib, pytest

SRC_DIRS = [pathlib.Path("src"), pathlib.Path("app"), pathlib.Path("integrations")]

class MaxTokensVisitor(ast.NodeVisitor):
    def __init__(self):
        self.violations = []

    def visit_Call(self, node):
        # Match anthropic_client.messages.create(...) and variants
        if (isinstance(node.func, ast.Attribute)
                and node.func.attr == "create"
                and isinstance(node.func.value, ast.Attribute)
                and node.func.value.attr == "messages"):
            kwarg_names = {kw.arg for kw in node.keywords}
            if "max_tokens" not in kwarg_names:
                self.violations.append(node.lineno)
        self.generic_visit(node)

def python_files():
    for d in SRC_DIRS:
        if d.exists():
            yield from d.rglob("*.py")

@pytest.mark.parametrize("path", list(python_files()))
def test_max_tokens_explicit(path):
    tree = ast.parse(path.read_text())
    visitor = MaxTokensVisitor()
    visitor.visit(tree)
    assert not visitor.violations, (
        f"{path}: messages.create() called without max_tokens at lines: "
        f"{visitor.violations}. Add max_tokens=<N> from the template's "
        f"max_output_tokens field."
    )

# tests/fitness/test_context_bounded.py
import ast, pathlib, pytest

CONTEXT_BUILDERS = [pathlib.Path("src/context"), pathlib.Path("app/context")]

class UnboundedIterationVisitor(ast.NodeVisitor):
    """Detect for-loops that append to a string/list inside a function
    whose name contains 'context', 'prompt', or 'messages'."""
    def __init__(self):
        self.violations = []
        self._current_fn = None

    def visit_FunctionDef(self, node):
        name_lower = node.name.lower()
        if any(kw in name_lower for kw in ("context", "prompt", "messages", "build")):
            prev = self._current_fn
            self._current_fn = node.name
            self.generic_visit(node)
            self._current_fn = prev
        else:
            self.generic_visit(node)

    def visit_For(self, node):
        if self._current_fn is None:
            self.generic_visit(node)
            return
        # Look for augmented assignment (+=) or .append() inside the loop body
        for child in ast.walk(node):
            if isinstance(child, ast.AugAssign):
                self.violations.append((self._current_fn, node.lineno, "+="))
            elif (isinstance(child, ast.Call)
                    and isinstance(child.func, ast.Attribute)
                    and child.func.attr == "append"):
                self.violations.append((self._current_fn, node.lineno, ".append()"))
        self.generic_visit(node)

def source_files():
    for d in CONTEXT_BUILDERS:
        if d.exists():
            yield from d.rglob("*.py")

@pytest.mark.parametrize("path", list(source_files()))
def test_context_is_bounded(path):
    tree = ast.parse(path.read_text())
    visitor = UnboundedIterationVisitor()
    visitor.visit(tree)

    # Flag only if there is no slice or islice call nearby — a slice is a cap
    # (This simplified check flags all loops; production version inspects slice nodes)
    assert not visitor.violations, (
        f"{path}: unbounded context iteration detected at:\n"
        + "\n".join(f"  {fn}() line {ln}: {op}" for fn, ln, op in visitor.violations)
        + "\nAdd a slice (items[:MAX_ITEMS]) or itertools.islice to cap context size."
    )

