import ast, pathlib, pytest

SRC_DIRS = [pathlib.Path("src"), pathlib.Path("app"), pathlib.Path("integrations")]

class UsageLogVisitor(ast.NodeVisitor):
    def __init__(self):
        self.violations = []

    def visit_FunctionDef(self, node):
        has_api_call = False
        has_usage_log = False

        for child in ast.walk(node):
            # Detect messages.create(...)
            if (isinstance(child, ast.Call)
                    and isinstance(child.func, ast.Attribute)
                    and child.func.attr == "create"
                    and isinstance(child.func.value, ast.Attribute)
                    and child.func.value.attr == "messages"):
                has_api_call = True

            # Detect any reference to "input_tokens" or "output_tokens" as a string
            # (covers structlog, logger.info(..., input_tokens=...), etc.)
            if isinstance(child, ast.Constant) and isinstance(child.value, str):
                if "input_tokens" in child.value or "output_tokens" in child.value:
                    has_usage_log = True
            if isinstance(child, ast.keyword) and child.arg in ("input_tokens", "output_tokens"):
                has_usage_log = True

        if has_api_call and not has_usage_log:
            self.violations.append(node.name)
        self.generic_visit(node)

def python_files():
    for d in SRC_DIRS:
        if d.exists():
            yield from d.rglob("*.py")

@pytest.mark.parametrize("path", list(python_files()))
def test_usage_logged(path):
    tree = ast.parse(path.read_text())
    visitor = UsageLogVisitor()
    visitor.visit(tree)
    assert not visitor.violations, (
        f"{path}: functions that call messages.create() without logging usage: "
        f"{visitor.violations}. Add structlog or logger.info with input_tokens= "
        f"and output_tokens= from response.usage."
    )

# tests/fitness/test_budget_alert_registered.py
import ast, pathlib, pytest

CONFIG_DIRS = [pathlib.Path("src"), pathlib.Path("app"), pathlib.Path("config")]

ALERT_PATTERNS = {
    "budget_exceeded",
    "cost_limit_exceeded",
    "on_cost_alert",
    "register_cost_handler",
    "cost_monitor",
}

class AlertRegistrationVisitor(ast.NodeVisitor):
    def __init__(self):
        self.found = False

    def visit_Call(self, node):
        # Check function name or attribute name for alert registration patterns
        name = ""
        if isinstance(node.func, ast.Name):
            name = node.func.id
        elif isinstance(node.func, ast.Attribute):
            name = node.func.attr
        if any(pat in name.lower() for pat in ALERT_PATTERNS):
            self.found = True
        self.generic_visit(node)

    def visit_Constant(self, node):
        # Also detect string-based event names like on("budget_exceeded", handler)
        if isinstance(node.value, str) and any(pat in node.value for pat in ALERT_PATTERNS):
            self.found = True

def all_python_files():
    for d in CONFIG_DIRS:
        if d.exists():
            yield from d.rglob("*.py")

def test_budget_alert_registered():
    found = False
    for path in all_python_files():
        tree = ast.parse(path.read_text())
        visitor = AlertRegistrationVisitor()
        visitor.visit(tree)
        if visitor.found:
            found = True
            break
    assert found, (
        "No budget alert handler registration found in config or app directories. "
        "Register a handler for budget_exceeded / cost_limit_exceeded events "
        "so budget overruns trigger an alert rather than silently continuing."
    )
